// MARK: - Secure Storage
class SecureStorage {
    func save<T: Codable>(_ object: T, forKey key: String) {
        do {
            let data = try JSONEncoder().encode(object)
            let encryptedData = SecurityManager.shared.encrypt(data)
            if let encrypted = encryptedData {
                UserDefaults.standard.set(encrypted, forKey: key)
            }
        } catch {
            print("Failed to save data: \(error)")
        }
    }
    
    func load<T: Codable>(forKey key: String) -> T? {
        guard let data = UserDefaults.standard.data(forKey: key) else { return nil }
        do {
            let decryptedData = SecurityManager.shared.decrypt(data)
            if let decrypted = decryptedData {
                return try JSONDecoder().decode(T.self, from: decrypted)
            }
        } catch {
            print("Failed to load data: \(error)")
        }
        return nil
    }
}

