// MARK: - Account Balance Service
class BalanceService {
    static let shared = BalanceService()
    
    private init() {}
    
    func getAccountBalance() -> Double {
        guard let account = DataManager.shared.loadAccount() else {
            return 0.0
        }
        return account.balance
    }
    
    func updateBalance(_ amount: Double, type: Transaction.TransactionType) {
        guard var account = DataManager.shared.loadAccount() else { return }
        
        switch type {
        case .debit:
            account.balance -= amount
        case .credit:
            account.balance += amount
        }
        
        DataManager.shared.saveAccount(account)
    }
    
    func formatCurrency(_ amount: Double) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = Locale(identifier: "en_US")
        return formatter.string(from: NSNumber(value: amount)) ?? "\(amount)"
    }
}

// MARK: - Extension for SHA256
extension String {
    func sha256() -> String {
        if let data = self.data(using: .utf8) {
            let hash = data.withUnsafeBytes { (bytes: UnsafeRawBufferPointer) in
                let hash = Insecure.SHA256.hash(data: Data(bytes))
                return Array(hash)
            }
            return hash.map { String(format: "%02x", $0) }.joined()
        }
        return self
    }
}

